class Solution {
    private static final int MOD = 1_000_000_007;
    private static final int[][] GCD = new int[7][7];
    static {
        for (int i = 1; i <= 6; ++i)
            for (int j = 1; j <= 6; ++j)
                GCD[i][j] = gcd(i, j);
    }
    private static int gcd(int a, int b) {
        return b == 0 ? a : gcd(b, a % b);
    }
    public int distinctSequences(int n) {
        if (n == 1) return 6;
        long[][][] dp = new long[n + 1][7][7];
        for (int a = 1; a <= 6; ++a)
            for (int b = 1; b <= 6; ++b)
                if (a != b && GCD[a][b] == 1)
                    dp[2][a][b] = 1;
        for (int len = 3; len <= n; ++len) {
            long[][] next = new long[7][7];
            for (int a = 1; a <= 6; ++a)
                for (int b = 1; b <= 6; ++b) {
                    if (dp[len - 1][a][b] == 0) continue;
                    for (int c = 1; c <= 6; ++c) {
                        if (c != a && c != b && GCD[b][c] == 1) {
                            next[b][c] = (next[b][c] + dp[len - 1][a][b]) % MOD;
                        }
                    }
                }
            dp[len] = next;
        }
        long ans = 0;
        for (int a = 1; a <= 6; ++a)
            for (int b = 1; b <= 6; ++b)
                ans = (ans + dp[n][a][b]) % MOD;
        return (int) ans;
    }
}
